from pathlib import Path
import openpyxl

def verify(workspace_path, external_services_path=None):
    xlsx_files = list(Path(workspace_path).glob('**/*.xlsx'))
    roster_files = [f for f in xlsx_files if 'employee_roster' in f.name.lower()]
    if not roster_files:
        return {'pass': False, 'score': 0.0, 'feedback': 'No employee_roster.xlsx file found in workspace'}

    wb = openpyxl.load_workbook(roster_files[0])
    ws = wb.worksheets[0]

    headers = [str(cell.value).strip().lower() if cell.value else '' for cell in ws[1]]

    def find_col(names):
        for name in names:
            for i, h in enumerate(headers):
                if name in h:
                    return i
        return None

    first_name_col = find_col(['first_name', 'first name', 'firstname'])
    last_name_col = find_col(['last_name', 'last name', 'lastname'])
    name_col = find_col(['name']) if first_name_col is None else None
    emp_id_col = find_col(['employee_id', 'employee id', 'emp_id', 'empid'])
    dept_col = find_col(['department', 'dept'])
    campus_col = find_col(['campus'])

    required = [
        {'first': 'Daniel', 'last': 'Yoon', 'dept': 'marketing', 'campus': 'west'},
        {'first': 'Priya', 'last': 'Kapoor', 'dept': 'finance', 'campus': 'main'},
        {'first': 'Marcus', 'last': 'Webb', 'dept': 'information technology', 'campus': 'main'},
    ]

    found = {r['last']: False for r in required}
    valid_dept = {r['last']: False for r in required}
    valid_campus = {r['last']: False for r in required}
    valid_id = {r['last']: False for r in required}

    for row in ws.iter_rows(min_row=2, values_only=True):
        row = list(row)
        if first_name_col is not None and last_name_col is not None:
            fname = str(row[first_name_col]).strip() if row[first_name_col] else ''
            lname = str(row[last_name_col]).strip() if row[last_name_col] else ''
        elif name_col is not None:
            parts = str(row[name_col]).strip().split() if row[name_col] else []
            fname = parts[0] if parts else ''
            lname = parts[-1] if len(parts) > 1 else ''
        else:
            continue

        for req in required:
            if fname.lower() == req['first'].lower() and lname.lower() == req['last'].lower():
                found[req['last']] = True
                emp_id = str(row[emp_id_col]).strip() if emp_id_col is not None and row[emp_id_col] else ''
                dept = str(row[dept_col]).strip().lower() if dept_col is not None and row[dept_col] else ''
                campus = str(row[campus_col]).strip().lower() if campus_col is not None and row[campus_col] else ''
                if emp_id and emp_id.lower() not in ('none', 'null', ''):
                    valid_id[req['last']] = True
                if req['dept'] in dept or dept in req['dept']:
                    valid_dept[req['last']] = True
                if req['campus'] in campus or campus in req['campus']:
                    valid_campus[req['last']] = True

    issues = []
    for req in required:
        last = req['last']
        if not found[last]:
            issues.append(f'{req["first"]} {last} not found in roster')
        else:
            if not valid_id[last]:
                issues.append(f'{last} has empty employee_id')
            if not valid_dept[last]:
                issues.append(f'{last} department mismatch (expected {req["dept"]})')
            if not valid_campus[last]:
                issues.append(f'{last} campus mismatch (expected {req["campus"]})')

    if issues:
        return {'pass': False, 'score': 0.0, 'feedback': 'Issues: ' + '; '.join(issues)}
    return {'pass': True, 'score': 1.0, 'feedback': 'All three employees (Yoon/Marketing/West, Kapoor/Finance/Main, Webb/IT/Main) found with valid employee_ids'}

