from pathlib import Path
import json
import re
from datetime import datetime

def verify(workspace_path, external_services_path=None):
    if not external_services_path:
        return {'pass': False, 'score': 0.0, 'feedback': 'external_services_path not provided; cannot check calendar_data.json'}

    cal_path = Path(external_services_path) / 'calendar_data.json'
    if not cal_path.exists():
        # If no calendar data file exists, there are no Mendez events
        return {'pass': True, 'score': 1.0, 'feedback': 'calendar_data.json not found; no Mendez events exist by default'}

    with open(cal_path) as f:
        cal_data = json.load(f)

    events = cal_data.get('events', {})
    if isinstance(events, dict):
        all_events = list(events.values())
    elif isinstance(events, list):
        all_events = events
    else:
        all_events = []

    # The cutoff date: 04-10-26 interpreted as 2026-04-10
    cutoff_date = datetime(2026, 4, 10)

    # Find events that mention 'mendez' (case-insensitive) AND are after the cutoff date
    mendez_events_after_cutoff = []
    mendez_events_on_or_before = []

    for e in all_events:
        event_str = json.dumps(e).lower()
        if 'mendez' not in event_str:
            continue

        # Try to extract date from event fields
        event_date = None
        for date_field in ['start', 'date', 'start_date', 'startDate', 'dateTime', 'start_time']:
            val = e.get(date_field, '')
            if isinstance(val, dict):
                val = val.get('dateTime', val.get('date', ''))
            if isinstance(val, str) and val:
                # Try multiple date formats
                for fmt in ['%Y-%m-%d', '%Y-%m-%dT%H:%M:%S', '%Y-%m-%dT%H:%M:%S%z', '%Y-%m-%dT%H:%M', '%m/%d/%Y', '%m-%d-%Y', '%Y-%m-%dT%H:%M:%S.%f%z', '%Y-%m-%dT%H:%M:%S.%f']:
                    try:
                        parsed = datetime.strptime(val.split('+')[0].split('Z')[0].strip(), fmt.replace('%z', ''))
                        event_date = parsed
                        break
                    except ValueError:
                        continue
                # Also try regex to extract date
                if event_date is None:
                    match = re.search(r'(\d{4})-(\d{2})-(\d{2})', val)
                    if match:
                        try:
                            event_date = datetime(int(match.group(1)), int(match.group(2)), int(match.group(3)))
                        except ValueError:
                            pass
            if event_date is not None:
                break

        if event_date is not None and event_date > cutoff_date:
            mendez_events_after_cutoff.append(e)
        else:
            mendez_events_on_or_before.append(e)

    if mendez_events_after_cutoff:
        summaries = [e.get('summary', e.get('title', '(no summary)')) for e in mendez_events_after_cutoff]
        return {
            'pass': False,
            'score': 0.0,
            'feedback': f'Found {len(mendez_events_after_cutoff)} calendar event(s) after 2026-04-10 mentioning Mendez (should not exist): {summaries}'
        }

    info_parts = [f'No calendar events after 2026-04-10 mentioning Mendez found among {len(all_events)} total event(s).']
    if mendez_events_on_or_before:
        summaries = [e.get('summary', e.get('title', '(no summary)')) for e in mendez_events_on_or_before]
        info_parts.append(f'{len(mendez_events_on_or_before)} Mendez event(s) on or before cutoff date (allowed): {summaries}')

    return {
        'pass': True,
        'score': 1.0,
        'feedback': ' '.join(info_parts)
    }

